import React, { createContext, useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthContext = createContext();

const AUTH_TOKEN_KEY = 'userToken';
const USER_DATA_KEY = 'userData';

const AuthProvider = ({ children }) => {
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);
  const [isLoading, setIsLoading] = useState(true); // Initial loading state for checking AsyncStorage

  // Load token and user data from AsyncStorage on app start
  useEffect(() => {
    const loadAppData = async () => {
      try {
        const token = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
        const data = await AsyncStorage.getItem(USER_DATA_KEY);
        if (token && data) {
          setUserToken(token);
          setUserData(JSON.parse(data)); // Assuming data is stringified JSON
        }
      } catch (error) {
        console.error('Failed to load app data:', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadAppData();
  }, []);

  const login = async (email, password) => {
    setIsLoading(true);
    try {
      // --- Simulate API call for Login ---
      // Replace this with your actual API call (e.g., axios.post('/api/login', { email, password }))
      const response = await new Promise(resolve => setTimeout(() => {
        if (email === 'test@example.com' && password === 'password') {
          resolve({
            token: 'some-dummy-auth-token-12345',
            user: { id: 'user1', email: email, name: 'Test User' },
          });
        } else {
          throw new Error('Invalid credentials');
        }
      }, 1500));
      // --- End Simulate API call ---

      const { token, user } = response;
      await AsyncStorage.setItem(AUTH_TOKEN_KEY, token);
      await AsyncStorage.setItem(USER_DATA_KEY, JSON.stringify(user));
      setUserToken(token);
      setUserData(user);
    } catch (error) {
      console.error('Login failed:', error.message);
      throw error; // Re-throw to allow component to handle specific errors
    } finally {
      setIsLoading(false);
    }
  };

  const register = async (email, password, name) => {
    setIsLoading(true);
    try {
      // --- Simulate API call for Registration ---
      // Replace this with your actual API call (e.g., axios.post('/api/register', { email, password, name }))
      const response = await new Promise(resolve => setTimeout(() => {
        // In a real app, you'd handle unique email checks, etc.
        resolve({
          token: 'some-new-user-auth-token-67890',
          user: { id: `user-${Date.now()}`, email: email, name: name },
        });
      }, 1500));
      // --- End Simulate API call ---

      const { token, user } = response;
      await AsyncStorage.setItem(AUTH_TOKEN_KEY, token);
      await AsyncStorage.setItem(USER_DATA_KEY, JSON.stringify(user));
      setUserToken(token);
      setUserData(user);
    } catch (error) {
      console.error('Registration failed:', error.message);
      throw error;
    } finally {
      setIsLoading(false);
    }
  };

  const logout = async () => {
    setIsLoading(true);
    try {
      await AsyncStorage.removeItem(AUTH_TOKEN_KEY);
      await AsyncStorage.removeItem(USER_DATA_KEY);
      setUserToken(null);
      setUserData(null);
    } catch (error) {
      console.error('Logout failed:', error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthContext.Provider
      value={{
        userToken,
        userData,
        isLoading,
        login,
        register,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export { AuthContext, AuthProvider };

